member.example:
Bind a CollectionViewModelBinder using a serialized field — the view array is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private CollectionViewModelBinder _items;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public IReadOnlyList<IViewModel> _items;
    }

Bind a ViewModelCollectionBinder<T> by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ItemView[] _itemViews;
        
        private ViewModelCollectionBinder<ItemView> _items;
        
        protected override void OnInitializedInternal()
        {
            _items = new ViewModelCollectionBinder<ItemView>(_itemViews);
        }
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public IReadOnlyList<IViewModel> _items;
    }
